<?php
 namespace League\CommonMark\Block\Renderer; use League\CommonMark\Block\Element\AbstractBlock; use League\CommonMark\Block\Element\HtmlBlock; use League\CommonMark\ElementRendererInterface; use League\CommonMark\EnvironmentInterface; use League\CommonMark\Util\ConfigurationAwareInterface; use League\CommonMark\Util\ConfigurationInterface; final class HtmlBlockRenderer implements BlockRendererInterface, ConfigurationAwareInterface { protected $config; public function render(AbstractBlock $block, ElementRendererInterface $htmlRenderer, bool $inTightList = false) { if (!($block instanceof HtmlBlock)) { throw new \InvalidArgumentException('Incompatible block type: ' . \get_class($block)); } if ($this->config->get('html_input') === EnvironmentInterface::HTML_INPUT_STRIP) { return ''; } if ($this->config->get('html_input') === EnvironmentInterface::HTML_INPUT_ESCAPE) { return \htmlspecialchars($block->getStringContent(), \ENT_NOQUOTES); } return $block->getStringContent(); } public function setConfiguration(ConfigurationInterface $configuration) { $this->config = $configuration; } } 